package com.i2i.voltwise.audit; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.time.Instant; import java.util.*; import java.util.UUID; public interface SnapshotRepository extends JpaRepository<ConsumptionSnapshot,Long>{ @Query("select s from ConsumptionSnapshot s where s.home.id=:homeId and s.capturedAt>=:since order by s.capturedAt") List<ConsumptionSnapshot> findRecent(@Param("homeId") UUID homeId,@Param("since") Instant since); }
